// Curated daily verses — well-known, meaningful, reasonably short.
const DAILY_AYAH_POOL = [
  "1:5","2:152","2:153","2:186","2:201","2:216","2:255","2:286",
  "3:8","3:139","3:159","3:185",
  "4:135","5:8","6:73","7:56","7:180","9:51","9:128",
  "11:88","13:11","13:28","14:7","15:88","16:97","16:128",
  "17:7","17:23","17:80","18:46",
  "20:14","21:107","24:35","25:74","27:62","28:77","29:69",
  "30:21","33:35","35:5","39:53","40:60","41:30","41:35",
  "42:43","49:11","49:13","51:50","55:13","57:4",
  "65:3","67:1","87:14","93:5","94:6"
];

function pickDailyAyah() {
  const day = Math.floor(Date.now() / 86400000); // days since epoch (UTC)
  return DAILY_AYAH_POOL[day % DAILY_AYAH_POOL.length];
}

async function renderDailyAyah() {
  const block    = document.getElementById("dailyAyah");
  if (!block) return;
  const arEl     = block.querySelector(".dailyArabic");
  const enEl     = block.querySelector(".dailyEnglish");
  const refEl    = block.querySelector(".dailyRef");
  const surahEl  = block.querySelector(".dailySurah");

  const id = pickDailyAyah();
  const [surahNum] = id.split(":");
  refEl.textContent   = id;
  surahEl.textContent = SURAH_NAMES[Number(surahNum)] || "";

  // Load the surah shard so we can pull the ayah's text
  try { await ensureSurahLoaded(surahNum); } catch (_) {}
  const rec = state.quranById.get(id);
  if (!rec) return;

  arEl.textContent = rec.arabic || "";
  arEl.removeAttribute("data-ph");
  const trans = (typeof getQuranTranslation === "function" && getQuranTranslation(id)) || rec.english || "";
  enEl.textContent = trans;
  enEl.classList.toggle("urdu-text", isUrduActive());

  block.tabIndex = 0;
  block.setAttribute("role", "button");
  const openIt = () => {
    enterResearchView();
    if (typeof openDetail === "function") openDetail(id);
  };
  block.onclick = openIt;
  block.onkeydown = (e) => {
    if (e.key === "Enter" || e.key === " ") { e.preventDefault(); openIt(); }
  };
}

function renderMoodHero() {
  const host = document.getElementById("moodCats");
  if (!host) return;
  host.innerHTML = "";

  for (const cat of TOPIC_CATEGORIES) {
    // Strip leading emoji from the label so the swatch dot does the work
    const cleanLabel = String(cat.label || "").replace(/^\s*\p{Extended_Pictographic}+\s*/u, "").trim();

    const section = document.createElement("section");
    section.className = "moodCat";

    const head = document.createElement("div");
    head.className = "moodCatHead";
    const h2 = document.createElement("h2");
    h2.className = "moodCatLabel";
    h2.textContent = cleanLabel;
    head.appendChild(h2);

    const note = document.createElement("span");
    note.className = "moodCatNote";
    note.textContent = `${cat.topics.length} topics`;
    head.appendChild(note);
    section.appendChild(head);

    const tiles = document.createElement("div");
    tiles.className = "moodTiles";
    for (const topic of cat.topics) {
      const tile = document.createElement("button");
      tile.type = "button";
      tile.className = "moodTile";
      const verseCount = (TOPIC_VERSES[topic] || []).length;
      tile.innerHTML = `
        <span class="moodTileText">
          <span class="moodTileLabel">${escapeHtml(topic)}</span>
          ${verseCount ? `<span class="moodTileMeta">${verseCount} verses</span>` : ""}
        </span>
      `;
      tile.addEventListener("click", () => selectTopic(topic));
      tiles.appendChild(tile);
    }
    section.appendChild(tiles);
    host.appendChild(section);
  }
}

function enterResearchView() {
  document.body.classList.remove("view-mood");
  document.body.classList.add("view-research");
}
function exitToMoodView() {
  document.body.classList.remove("view-research");
  document.body.classList.add("view-mood");
  // Reset any active drill state so returning home feels clean
  state.selectedAyahId = null;
  state.detailHistory  = [];
  if (typeof updateBackButton === "function") updateBackButton();
  if (typeof setDetailState === "function") setDetailState("empty");
  if (els.mainQuery) els.mainQuery.value = "";
  if (typeof clearSmartHint === "function") clearSmartHint();
  state.lastResults = [];
  if (typeof renderResults === "function") renderResults([]);
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function wireMoodFirstView() {
  // Default to mood view on first load
  if (!document.body.classList.contains("view-research")
   && !document.body.classList.contains("view-mood")) {
    document.body.classList.add("view-mood");
  }

  // Header search trigger → research view + focus input
  const trig = document.getElementById("searchTrigger");
  if (trig) {
    trig.addEventListener("click", () => {
      enterResearchView();
      requestAnimationFrame(() => els.mainQuery?.focus());
    });
  }

  // Back-home pill (visible in research view)
  const home = document.getElementById("backHome");
  if (home) home.addEventListener("click", exitToMoodView);

  // ⌘K / Ctrl+K opens search anywhere
  document.addEventListener("keydown", e => {
    const k = e.key?.toLowerCase();
    if ((e.metaKey || e.ctrlKey) && k === "k") {
      e.preventDefault();
      enterResearchView();
      requestAnimationFrame(() => els.mainQuery?.focus());
    }
    // Esc returns to mood view if nothing else is open
    if (e.key === "Escape" && document.body.classList.contains("view-research")) {
      const anyModalOpen = ["wordModal","feelingsModal","statsModal","prophetsModal"]
        .some(id => {
          const m = document.getElementById(id);
          return m && !m.classList.contains("hidden");
        });
      const menu = document.getElementById("overflowMenu");
      const menuOpen = menu && !menu.classList.contains("hidden");
      if (!anyModalOpen && !menuOpen) exitToMoodView();
    }
  });

  // Hero footer buttons
  document.querySelectorAll('[data-mood-action]').forEach(btn => {
    btn.addEventListener("click", () => {
      const action = btn.dataset.moodAction;
      if (action === "search") {
        enterResearchView();
        requestAnimationFrame(() => els.mainQuery?.focus());
      } else if (action === "prophets") {
        if (typeof openProphetsModal === "function") openProphetsModal();
      }
    });
  });
}

async function selectTopic(topicName) {
  closeFeelingsModal();
  showLanding(false);
  enterResearchView();

  const ayahIds = TOPIC_VERSES[topicName] || [];
  if (!ayahIds.length) return;

  setBadge("warn", `Loading "${topicName}"…`);

  // Load all required surahs in parallel
  const surahs = [...new Set(ayahIds.map(id => id.split(":")[0]))];
  try {
    await Promise.all(surahs.map(s => ensureSurahLoaded(s).catch(() => {})));
  } catch (_) {}

  // Build result records — preserve topic order
  const records = ayahIds.map(id => state.quranById.get(id)).filter(Boolean);

  // Show in search results panel
  if (els.mainQuery) els.mainQuery.value = topicName;
  state.selectedAyahId = null;
  setDetailState("empty");
  updateTabCounts(0, 0, 0, 0);
  renderResults(records);
  if (els.searchHint) els.searchHint.textContent = `Showing ${records.length} verses on "${topicName}"`;
  setBadge("ok", `${records.length} verses · ${topicName}`);
}

function isUrduActive() {
  return TRANSLATION_OPTIONS.find(o => o.id === state.activeTranslation)?.lang === "ur";
}

function getQuranTranslation(ayahId) {
  const id = state.activeTranslation;
  if (id === "en_default") return null;
  return state.translationData.get(id)?.[ayahId] ?? null;
}

function getHadithUrduText(hadithId) {
  if (!isUrduActive()) return null;
  const serial = hadithSerialFromId(hadithId);
  if (!serial) return null;
  for (const shard of state.urHadithShardCache.values()) {
    const t = shard[String(serial)];
    if (t) return t;
  }
  return null;
}

async function loadTranslation(id) {
  if (id === "en_default" || state.translationData.has(id)) return;
  const opt = TRANSLATION_OPTIONS.find(o => o.id === id);
  if (!opt?.path) return;
  // ?v=3 in URL acts as cache-buster when data format changes.
  // force-cache: serve from browser/SW cache when available.
  const fp = resolveDataPath(opt.path) + "?v=3";
  const res = await fetch(fp, { cache: "force-cache" });
  if (!res.ok) throw new Error(`HTTP ${res.status} for ${fp}`);
  const data = await res.json();
  state.translationData.set(id, data);
}

function findUrHadithShardFile(serial) {
  for (const x of state.urHadithShardMap || [])
    if (serial >= x.start && serial <= x.end) return x.file;
  return null;
}

async function preloadUrHadithShards(hadithIds) {
  if (!isUrduActive() || !state.urHadithShardMap) return;
  const files = new Set();
  for (const hid of hadithIds) {
    const serial = hadithSerialFromId(hid);
    if (!serial) continue;
    const file = findUrHadithShardFile(serial);
    if (file && !state.urHadithShardCache.has(file)) files.add(file);
  }
  if (!files.size) return;
  await Promise.all([...files].map(async file => {
    const fp = resolveDataPath(file);
    const res = await fetch(fp, { cache: "force-cache" });
    if (!res.ok) throw new Error(`HTTP ${res.status} for ${fp}`);
    const data = await res.json();
    state.urHadithShardCache.set(file, data);
  }));
}

// ── Helpers ────────────────────────────────────────────────

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function resolveDataPath(path) {
  let p = String(path || "").trim().replace(/\\/g, "/").replace(/^\.?\//, "");
  if (!p) return p;
  return p.startsWith("data/") ? p : `data/${p}`;
}

async function fetchJson(path) {
  const fp = resolveDataPath(path);
  if (state.jsonCache.has(fp))   return state.jsonCache.get(fp);
  if (state.pendingJson.has(fp)) return state.pendingJson.get(fp);

  const p = (async () => {
    const res = await fetch(fp, { cache: "force-cache" });
    if (!res.ok) {
      let txt = "";
      try { txt = await res.text(); } catch (_) {}
      throw new Error(`HTTP ${res.status} for ${fp}${txt ? ` | ${txt.slice(0,120)}` : ""}`);
    }
    try {
      const data = await res.json();
      state.jsonCache.set(fp, data);
      state.pendingJson.delete(fp);
      return data;
    } catch (err) {
      state.pendingJson.delete(fp);
      throw new Error(`Invalid JSON at ${fp}: ${err.message}`);
    }
  })().catch(err => { state.pendingJson.delete(fp); throw err; });

  state.pendingJson.set(fp, p);
  return p;
}

function setBadge(kind, text) {
  els.statusBadge.className = `badge ${kind}`;
  els.statusBadge.textContent = text;
}

function unique(arr) { return [...new Set(arr)]; }

function surahFromAyahId(ayahId) { return String(ayahId).split(":")[0]; }

function surahName(ayahId) {
  return SURAH_NAMES[Number(surahFromAyahId(ayahId))] || "";
}

function fmtAyahId(ayahId) {
  const name = surahName(ayahId);
  return name ? `${ayahId} — ${name}` : ayahId;
}

function escapeHtml(s) {
  return String(s ?? "")
    .replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");
}

function fmtScore(x) {
  const n = Number(x);
  if (!Number.isFinite(n)) return "—";
  return `${Math.max(0, Math.min(100, Math.round(n)))}%`;
}

function showLanding(show) {
  if (els.landingCard) els.landingCard.style.display = show ? "" : "none";
}

function setDetailState(mode) {
  if (!els.detailWrap) return;
  els.detailWrap.dataset.state = mode;
  if (mode === "detail") {
    els.detailEmpty?.classList.add("hidden");
    els.detailView?.classList.remove("hidden");
  } else {
    els.detailEmpty?.classList.remove("hidden");
    els.detailView?.classList.add("hidden");
  }
}

function updateTabCounts(semQ, semH, lexQ, lexH) {
  const semTotal = semQ + semH;
  const lexTotal = lexQ + lexH;
  if (els.semCount) els.semCount.textContent = semTotal > 0 ? `(${semTotal})` : "";
  if (els.lexCount) els.lexCount.textContent = lexTotal > 0 ? `(${lexTotal})` : "";
}

// ── Search type toggle ──────────────────────────────────────

function setSearchType(type) {
  state.activeSearchType = type;
  document.querySelectorAll(".typeBtn").forEach(btn => {
    btn.classList.toggle("active", btn.dataset.type === type);
  });
  els.mainQuery.setAttribute("dir", type === "ar" ? "rtl" : "ltr");
  els.mainQuery.placeholder = SEARCH_PLACEHOLDERS[type] || "";
  if (els.searchHint) els.searchHint.textContent = SEARCH_HINTS[type] || "";
  els.mainQuery.focus();
}

// Phase 3 — Intent detection. Returns "id" / "ar" / "en" / null.
function detectQueryIntent(q) {
  const s = String(q || "").trim();
  if (!s) return null;
  if (/^\d+\s*[:.\-]\s*\d+/.test(s)) return "id";
  if (/[؀-ۿ]/.test(s))     return "ar";
  return "en";
}

// Auto-switch typeToggle as user types — unless they've manually picked a mode
// (or the special "smart" mode is active). Reset on Clear.
function applyAutoIntent() {
  if (state.modeWasManual) return;
  if (state.activeSearchType === "smart") return;
  const intent = detectQueryIntent(els.mainQuery?.value);
  if (!intent || intent === state.activeSearchType) return;
  setSearchType(intent);
  // setSearchType refocuses — keep caret position so typing isn't interrupted.
  const el = els.mainQuery;
  if (el && document.activeElement === el) {
    const pos = el.value.length;
    try { el.setSelectionRange(pos, pos); } catch (_) {}
  }
}

// ── Arabic / English normalisation ─────────────────────────

function normalizeArabic(s) {
  return String(s || "")
    .replace(/[ؐ-ًؚ-ٰٟۖ-ۭ]/g, "")
    .replace(/ـ/g, "")
    .replace(/[أإآ]/g, "ا").replace(/ى/g, "ي").replace(/[ؤئ]/g, "ء")
    .replace(/[^؀-ۿ0-9\s]/g, " ")
    .replace(/\s+/g, " ").trim();
}

function normalizeEnglish(s) {
  return String(s || "").toLowerCase().replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ").trim();
}

function trigrams(token) {
  if (token.length <= 3) return [token];
  const out = [];
  for (let i = 0; i < token.length - 2; i++) out.push(token.slice(i, i+3));
  return out;
}

function maxAllowedEdits(len) {
  if (len <= 4) return 1;
  if (len <= 8) return 2;
  return 3;
}

function stemVariantsEn(token) {
  const vars = new Set([token]);
  if (token.endsWith("ing") && token.length > 5) vars.add(token.slice(0,-3));
  if (token.endsWith("ed")  && token.length > 4) vars.add(token.slice(0,-2));
  if (token.endsWith("es")  && token.length > 4) vars.add(token.slice(0,-2));
  if (token.endsWith("s")   && token.length > 3) vars.add(token.slice(0,-1));
  if (token.endsWith("ies") && token.length > 5) vars.add(token.slice(0,-3)+"y");
  return [...vars];
}

function levenshtein(a, b) {
  if (a === b) return 0;
  const m = a.length, n = b.length;
  if (!m) return n; if (!n) return m;
  let prev = Array.from({length: n+1}, (_,i) => i);
  let curr = new Array(n+1);
  for (let i = 1; i <= m; i++) {
    curr[0] = i;
    const ca = a.charCodeAt(i-1);
    for (let j = 1; j <= n; j++) {
      const cost = ca === b.charCodeAt(j-1) ? 0 : 1;
      curr[j] = Math.min(prev[j]+1, curr[j-1]+1, prev[j-1]+cost);
    }
    [prev, curr] = [curr, prev];
  }
  return prev[n];
}

// ── Data loading ────────────────────────────────────────────

async function ensureSurahLoaded(surah) {
  surah = String(surah);
  if (state.loadedSurahs.has(surah)) return;
  const qPath = state.shardMapQuran?.[surah];
  const pPath = state.shardMapPairs?.[surah];
  if (!qPath) throw new Error(`No Quran shard for surah ${surah}`);
  if (!pPath) throw new Error(`No pairs shard for surah ${surah}`);
  const [qShard, pShard] = await Promise.all([fetchJson(qPath), fetchJson(pPath)]);
  for (const rec of qShard) state.quranById.set(rec.ayah_id, rec);
  for (const rec of pShard) state.pairsByAyah.set(rec.ayah_id, rec);
  state.loadedSurahs.add(surah);
}

// ── Tafsir scaffold (loader + renderer) ────────────────────

async function ensureTafsirIndex() {
  if (state.tafsirIndex !== null) return state.tafsirIndex;
  const path = state.manifest?.paths?.tafsir_index || "data/meta/tafsir_index.json";
  try {
    const idx = await fetchJson(path);
    state.tafsirIndex = idx && typeof idx === "object" ? idx : { sources: {} };
  } catch (_) {
    state.tafsirIndex = { sources: {} };
  }
  return state.tafsirIndex;
}

async function ensureTafsirLoaded(surah, source) {
  if (!source) return null;
  const surahStr = String(surah);
  state.tafsirBySource[source] = state.tafsirBySource[source] || {};
  if (state.tafsirBySource[source][surahStr]) return state.tafsirBySource[source][surahStr];

  await ensureTafsirIndex();
  const meta = state.tafsirIndex?.sources?.[source];
  if (!meta?.shard_pattern) {
    state.tafsirBySource[source][surahStr] = {};
    return {};
  }
  const padded = surahStr.padStart(3, "0");
  const url = meta.shard_pattern.replace("{NNN}", padded);
  try {
    const data = await fetchJson(url);
    state.tafsirBySource[source][surahStr] = (data && typeof data === "object") ? data : {};
  } catch (_) {
    state.tafsirBySource[source][surahStr] = {};   // negative cache so we don't refetch 404s
  }
  return state.tafsirBySource[source][surahStr];
}

function getTafsir(ayahId, source) {
  const [surah] = String(ayahId).split(":");
  return state.tafsirBySource?.[source]?.[surah]?.[ayahId] || null;
}

// Translation → preferred tafsir source. Falls back to any available source.
function defaultTafsirForTranslation(transId) {
  const sources = state.tafsirIndex?.sources || {};
  const keys = Object.keys(sources);
  if (!keys.length) return null;
  const id = String(transId || "");
  if (id.startsWith("ur") && sources.maududi)   return "maududi";
  if (id.startsWith("en") && sources.ibn_kathir) return "ibn_kathir";
  // Fallback: prefer source whose lang matches translation lang prefix
  const langPrefix = id.split("_")[0];
  const match = keys.find(k => sources[k].lang === langPrefix);
  return match || keys[0];
}

function renderTafsirTabs(currentSource) {
  const tabsEl = document.querySelector("#tafsirBlock .tafsirTabs");
  if (!tabsEl) return;
  const sources = state.tafsirIndex?.sources || {};
  const keys = Object.keys(sources);
  if (keys.length < 2) { tabsEl.innerHTML = ""; return; }
  tabsEl.innerHTML = keys.map(k => {
    const active = k === currentSource ? " active" : "";
    return `<button type="button" class="tafsirTab${active}" data-src="${escapeHtml(k)}" role="tab" aria-selected="${k === currentSource}">${escapeHtml(sources[k].label || k)}</button>`;
  }).join("");
}

async function renderAnchorTafsir(ayahId) {
  const block = document.getElementById("tafsirBlock");
  if (!block) return;
  const labelEl = block.querySelector(".tafsirLabel");
  const textEl  = block.querySelector(".tafsirText");
  if (!labelEl || !textEl) return;

  await ensureTafsirIndex();
  const sources = state.tafsirIndex?.sources || {};
  if (!Object.keys(sources).length) { block.classList.add("hidden"); return; }

  const source = state.activeTafsirSource && sources[state.activeTafsirSource]
    ? state.activeTafsirSource
    : defaultTafsirForTranslation(state.activeTranslation);
  if (!source) { block.classList.add("hidden"); return; }

  const meta = sources[source];
  block.classList.remove("hidden");
  labelEl.innerHTML = `Tafsir <span class="tafsirAuthor">— ${escapeHtml(meta.author || meta.label || "")}</span>`;
  renderTafsirTabs(source);

  // Skeleton while shard loads
  textEl.innerHTML = `
    <div class="skeletonLine wide"></div>
    <div class="skeletonLine wide"></div>
    <div class="skeletonLine med"></div>
  `;

  const surahNum = String(ayahId).split(":")[0];
  await ensureTafsirLoaded(surahNum, source);

  // Guard against stale render if the user opened a different ayah in the meantime
  if (state.selectedAyahId && state.selectedAyahId !== ayahId) return;

  const text = getTafsir(ayahId, source);
  if (!text) {
    textEl.innerHTML = `<p class="tafsirEmpty">No commentary from ${escapeHtml(meta.label || source)} for this verse yet.</p>`;
    return;
  }
  const isUrdu = meta.lang === "ur";
  const safe = escapeHtml(text);
  textEl.innerHTML = `<div class="tafsirBody${isUrdu ? " urdu-text" : ""}"${isUrdu ? ' dir="rtl"' : ""}>${safe}</div>`;
}

// Tab-strip click handler (event delegation — block exists on first render)
document.addEventListener("click", (e) => {
  const tab = e.target.closest?.("#tafsirBlock .tafsirTab");
  if (!tab) return;
  state.activeTafsirSource = tab.dataset.src;
  if (state.selectedAyahId) renderAnchorTafsir(state.selectedAyahId);
});

function findHadithShardFileBySerial(serial) {
  for (const x of state.shardMapHadith || [])
    if (serial >= x.start && serial <= x.end) return x.file;
  return null;
}

function hadithSerialFromId(hid) {
  const parts = String(hid).split("|");
  const s = Number(parts[parts.length-1]);
  return Number.isFinite(s) ? s : null;
}

async function ensureHadithById(hadithId) {
  if (state.hadithById.has(hadithId)) return;
  const serial = hadithSerialFromId(hadithId);
  if (serial == null) throw new Error(`Bad hadith id: ${hadithId}`);
  const file = findHadithShardFileBySerial(serial);
  if (!file) throw new Error(`No hadith shard for serial ${serial}`);
  if (!state.loadedHadithShardFiles.has(file)) {
    const shard = await fetchJson(file);
    for (const rec of shard) state.hadithById.set(rec.hadith_id, rec);
    state.loadedHadithShardFiles.add(file);
  }
}

async function loadSurahsParallel(surahs) {
  const uniq = unique((surahs || []).map(String).filter(Boolean));
  if (!uniq.length) return;
  await Promise.all(uniq.map(s => ensureSurahLoaded(s)));
}

async function preloadHadithIds(ids) {
  const uniq = unique((ids || []).filter(Boolean));
  if (!uniq.length) return;
  await Promise.all(uniq.map(async hid => {
    try { await ensureHadithById(hid); } catch (err) { console.error(err); }
  }));
}

// ── Search ──────────────────────────────────────────────────

async function searchByAyahId(raw) {
  const norm = String(raw || "").trim();
  if (state.searchCache.id.has(norm)) return state.searchCache.id.get(norm);
  const m = norm.match(/^(\d+)\s*:\s*(\d+)$/);
  if (!m) return [];
  const id = `${Number(m[1])}:${Number(m[2])}`;
  await ensureSurahLoaded(surahFromAyahId(id));
  const rec = state.quranById.get(id);
  const out = rec ? [rec] : [];
  state.searchCache.id.set(norm, out);
  return out;
}

async function searchByArabicKeyword(raw) {
  const norm = normalizeArabic(raw);
  if (!norm) return [];
  if (state.searchCache.ar.has(norm)) return state.searchCache.ar.get(norm);
  const ids = state.arTokenToAyah?.[norm] || [];
  await loadSurahsParallel(unique(ids.map(surahFromAyahId)));
  const out = ids.map(id => state.quranById.get(id)).filter(Boolean);
  state.searchCache.ar.set(norm, out);
  return out;
}

async function searchBySmart(raw) {
  const q = String(raw || "").trim();
  if (!q) return [];

  const isArabic = /[؀-ۿ]/.test(q);
  const lang = isArabic ? "ar" : "en";

  let payload;
  try {
    const res = await fetch(SMART_SEARCH_ENDPOINT, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ query: q, lang }),
    });
    if (!res.ok) {
      const errBody = await res.text();
      throw new Error(`API ${res.status}: ${errBody.slice(0, 180)}`);
    }
    payload = await res.json();
  } catch (err) {
    setBadge("err", "Smart Search failed: " + (err.message || err).slice(0, 120));
    return [];
  }

  const items = Array.isArray(payload?.results) ? payload.results : [];
  if (!items.length) return [];

  // Make sure the surah shards are loaded so we can return full ayah records
  // (with roots/tokens/etc) consistent with what the rest of the UI expects.
  const surahsNeeded = unique(items.map((r) => Number(r.surah)).filter(Boolean));
  await loadSurahsParallel(surahsNeeded);

  // Tokenize query once so we can mark which results also literally contain the
  // user's words (hybrid annotation: semantic match + keyword match = strong signal).
  const queryTokens = isArabic
    ? normalizeArabic(q).split(" ").filter(t => t.length >= 2)
    : normalizeEnglish(q).split(" ").filter(t => t.length >= 2);

  const out = [];
  for (const r of items) {
    const local = state.quranById.get(r.ayah_id);
    const base = local || {
      ayah_id: r.ayah_id,
      surah: r.surah,
      ayah: r.ayah,
      arabic: r.arabic_text,
      english: r.english_text,
      roots_ordered: r.roots || [],
      tokens_ordered: [],
      vec_preview: [],
    };

    const haystack = isArabic
      ? normalizeArabic(base.arabic || "")
      : normalizeEnglish(base.english || "");
    const hasKeywordMatch = queryTokens.length > 0 &&
      queryTokens.some(tok => haystack.includes(tok));

    // Spread so we don't mutate the cached state.quranById record.
    out.push({
      ...base,
      _rerank_score: typeof r.rerank_score === "number" ? r.rerank_score : null,
      _embed_score:  typeof r.embed_score  === "number" ? r.embed_score  : null,
      _hasKeywordMatch: hasKeywordMatch,
    });
  }

  state.lastSmartCached = !!payload?.cached;
  state.lastSmartTimings = payload?.timings_ms || null;
  state.lastSmartQuery = q;
  state.lastSmartLang = lang;
  return out;
}

function showSmartHint({ topScore, lang, query }) {
  if (!els.smartHint) return;
  // Hide if signal is strong enough.
  if (topScore == null || topScore >= SMART_WEAK_THRESHOLD) {
    els.smartHint.classList.add("hidden");
    els.smartHint.innerHTML = "";
    return;
  }
  const suggestions = (lang === "ar" ? SMART_SUGGESTIONS_AR : SMART_SUGGESTIONS_EN)
    .filter(s => s.toLowerCase() !== String(query || "").toLowerCase())
    .slice(0, 5);
  const chips = suggestions.map(s =>
    `<button type="button" class="hintChip" data-suggest="${escapeHtml(s)}">${escapeHtml(s)}</button>`
  ).join("");
  els.smartHint.innerHTML = `
    <div class="hintTitle">Weak match for "${escapeHtml(query)}"</div>
    <div class="hintSub">The AI wasn't very confident. Try a more conceptual phrasing:</div>
    <div class="hintChips">${chips}</div>
  `;
  els.smartHint.classList.remove("hidden");
  els.smartHint.querySelectorAll(".hintChip").forEach(btn => {
    btn.addEventListener("click", () => {
      els.mainQuery.value = btn.dataset.suggest;
      runSearch();
    });
  });
}

function clearSmartHint() {
  if (!els.smartHint) return;
  els.smartHint.classList.add("hidden");
  els.smartHint.innerHTML = "";
}

async function searchByEnglishSmart(raw) {
  const norm = normalizeEnglish(raw);
  if (!norm) return [];
  if (state.searchCache.en.has(norm)) return state.searchCache.en.get(norm);

  const toks = norm.split(" ").filter(Boolean);
  if (!toks.length) return [];

  const matchedAyahScores = new Map();
  const matchedTokenCounts = new Map();
  let lastYield = performance.now();

  for (let ti = 0; ti < toks.length; ti++) {
    const qt = toks[ti];
    const variants = stemVariantsEn(qt);
    const candidateScores = new Map();

    for (const v of variants) {
      for (const g of trigrams(v)) {
        for (const t of (state.enTriToTokens?.[g] || []))
          candidateScores.set(t, (candidateScores.get(t) || 0) + 1);
      }
    }

    const candidates = Array.from(candidateScores.entries())
      .sort((a,b) => b[1]-a[1] || a[0].length-b[0].length)
      .slice(0, 1200).map(x => x[0]);

    const maxEd = maxAllowedEdits(qt.length);
    const good = [];
    let checked = 0;

    for (const t of candidates) {
      checked++;
      if (Math.abs(t.length - qt.length) > maxEd) continue;
      let bestD = 999;
      for (const v of variants) {
        const d = levenshtein(v, t);
        if (d < bestD) bestD = d;
        if (bestD === 0) break;
      }
      if (bestD <= maxEd) good.push({ t, d: bestD, trigramScore: candidateScores.get(t) || 0 });
      if (checked % 500 === 0) {
        const now = performance.now();
        if (now - lastYield > 10) { await sleep(0); lastYield = now; }
      }
    }

    good.sort((a,b) => a.d-b.d || (b.trigramScore||0)-(a.trigramScore||0));
    const ayatMatchedThisToken = new Set();

    for (const m of good.slice(0, 12)) {
      const ids = state.enTokenToAyah?.[m.t] || [];
      const base = (maxEd - m.d + 1);
      const exactBonus = m.d === 0 ? 2 : 0;
      for (const id of ids) {
        matchedAyahScores.set(id, (matchedAyahScores.get(id) || 0) + base + exactBonus);
        ayatMatchedThisToken.add(id);
      }
    }
    for (const id of ayatMatchedThisToken)
      matchedTokenCounts.set(id, (matchedTokenCounts.get(id) || 0) + 1);

    if (toks.length > 2) setBadge("warn", `Searching… (${ti+1}/${toks.length})`);
  }

  const minMatch = Math.max(1, Math.ceil(toks.length * 0.6));
  const ranked = Array.from(matchedAyahScores.entries())
    .filter(([id]) => (matchedTokenCounts.get(id) || 0) >= minMatch)
    .sort((a,b) => b[1]-a[1]).slice(0, 200).map(x => x[0]);

  await loadSurahsParallel(unique(ranked.map(surahFromAyahId)));
  const out = ranked.map(id => state.quranById.get(id)).filter(Boolean);
  state.searchCache.en.set(norm, out);
  return out;
}

// ── Rendering ───────────────────────────────────────────────

function renderResults(list, { preserveOrder = false } = {}) {
  // By default sort by surah:verse ascending (good for keyword/ID search).
  // For semantic results (Smart Search) we preserve the reranker's ordering instead.
  list = (list || []).slice();
  if (!preserveOrder) {
    list.sort((a, b) => {
      const [as, av] = a.ayah_id.split(":").map(Number);
      const [bs, bv] = b.ayah_id.split(":").map(Number);
      return as - bs || av - bv;
    });
  }
  state.lastResults = list;
  els.resultsList.innerHTML = "";
  if (els.resultsCount) els.resultsCount.textContent = list.length > 0 ? `(${list.length})` : "";

  if (!list.length) {
    els.resultsList.classList.add("empty");
    els.resultsList.textContent = "No results found.";
    return;
  }
  els.resultsList.classList.remove("empty");

  const urdu = isUrduActive();
  for (const rec of list) {
    const surahNum  = Number(surahFromAyahId(rec.ayah_id));
    const surahNm   = SURAH_NAMES[surahNum] || "";
    const transText = getQuranTranslation(rec.ayah_id);
    const displayEn = transText || rec.english || "";

    // Smart Search confidence badge (only when rerank score is present).
    let scoreBadge = "";
    if (typeof rec._rerank_score === "number") {
      const pct = Math.max(0, Math.min(100, Math.round(rec._rerank_score * 100)));
      const tier = rec._rerank_score >= 0.5 ? "high" : rec._rerank_score >= 0.2 ? "mid" : "low";
      const kw = rec._hasKeywordMatch
        ? `<span class="kwMatch" title="Also literally contains your keywords">📖</span>`
        : "";
      scoreBadge = `<div class="scoreBadge ${tier}" title="Reranker confidence">${pct}%${kw}</div>`;
    }

    const div = document.createElement("div");
    div.className = "item" + (state.selectedAyahId === rec.ayah_id ? " selected" : "");
    div.innerHTML = `
      <div class="itemId">
        <div class="ayahNum">${escapeHtml(rec.ayah_id)}</div>
        <div class="ayahName">${escapeHtml(surahNm)}</div>
        ${scoreBadge}
      </div>
      <div>
        <div class="txt" dir="rtl">${escapeHtml(rec.arabic || "")}</div>
        <div class="subtxt${urdu ? " urdu-text" : ""}">${escapeHtml(displayEn)}</div>
      </div>
    `;
    div.onclick = () => openDetail(rec.ayah_id);
    els.resultsList.appendChild(div);
  }
}

function setTab(name) {
  document.querySelectorAll(".tab").forEach(t => t.classList.toggle("active", t.dataset.tab === name));
  els.tabSemantic.classList.toggle("hidden", name !== "semantic");
  els.tabLexical.classList.toggle("hidden",  name !== "lexical");
}

document.querySelectorAll(".tab").forEach(btn => {
  btn.addEventListener("click", () => setTab(btn.dataset.tab));
});

function makeWordChips(values) {
  if (!values || !values.length) return `<span class="small">—</span>`;
  return values.map(v => `<span class="rootChip" dir="rtl">${escapeHtml(v)}</span>`).join("");
}

function makeSharedChips(label, values) {
  if (!values || !values.length) return "";
  const chips = values.map(v => `<span class="rootChip" dir="rtl">${escapeHtml(v)}</span>`).join("");
  return `<div class="sharedRow"><span class="sharedLabel">${escapeHtml(label)}</span><div class="chipGroup">${chips}</div></div>`;
}

function renderPairList(container, items, options = {}) {
  const kind              = options.kind || "quran";
  const emptyMessage      = options.emptyMessage || "No items.";
  const sharedRootsLabel  = options.sharedRootsLabel  || "Shared root words";
  const sharedTokensLabel = options.sharedTokensLabel || "Shared Arabic words";
  const showRootsLine     = Boolean(options.showRootsLine);
  const showCommonHadithTokens = Boolean(options.showCommonHadithTokens);

  container.innerHTML = "";
  if (!items || !items.length) {
    container.innerHTML = `<div class="empty">${escapeHtml(emptyMessage)}</div>`;
    return;
  }

  for (const it of items) {
    const div = document.createElement("div");
    div.className = "pair";

    const isQuranPair = kind === "quran";
    if (isQuranPair) {
      div.classList.add("clickable");
      div.title = "Click to explore pairs for this ayah";
      div.addEventListener("click", () => drillTo(it.id));
    }

    const pairSurahNum  = Number(surahFromAyahId(it.id));
    const pairSurahName = isQuranPair ? (SURAH_NAMES[pairSurahNum] || "") : "";
    const idHtml = isQuranPair
      ? `<div class="pairIdBlock">
           <div class="pairNum">${escapeHtml(it.id)}</div>
           ${pairSurahName ? `<div class="pairSurah">${escapeHtml(pairSurahName)}</div>` : ""}
         </div>`
      : `<div class="pairIdBlock"><div class="pairNum">${escapeHtml(it.id)}</div></div>`;

    const urdu = isUrduActive();
    let body = "";
    if (isQuranPair) {
      const rec = state.quranById.get(it.id);
      if (rec) {
        const transText = getQuranTranslation(it.id);
        const displayEn = transText || rec.english || "";
        body = `<div class="pairBody"><div dir="rtl">${escapeHtml(rec.arabic || "")}</div></div>
           <div class="pairBodySmall${urdu ? " urdu-text" : ""}">${escapeHtml(displayEn)}</div>`;
      } else {
        body = `<div class="pairBodySmall">Loading…</div>`;
      }
    } else {
      const h = state.hadithById.get(it.id);
      if (h) {
        const urText = getHadithUrduText(it.id);
        const displayText = urText || h.english || "";
        body = `<div class="pairBody"><div dir="rtl">${escapeHtml(h.arabic || "")}</div></div>`;
        if (displayText) {
          body += `<div class="pairBodySmall${urdu && urText ? " urdu-text" : ""}">${escapeHtml(displayText)}</div>`;
        } else {
          body += `<div class="pairBodySmall">${escapeHtml(h.book || "")} — ${escapeHtml(h.reference || "")}</div>`;
        }
      } else {
        body = `<div class="pairBodySmall">Loading…</div>`;
      }
    }

    const shared = Array.isArray(it.shared_tokens) ? it.shared_tokens : [];
    let sharedBlock = "";
    if (showRootsLine) {
      sharedBlock = makeSharedChips(sharedRootsLabel, shared);
    } else if (showCommonHadithTokens) {
      sharedBlock = makeSharedChips(sharedTokensLabel, shared);
    } else if (shared.length) {
      sharedBlock = makeSharedChips(sharedTokensLabel, shared);
    }

    div.innerHTML = `
      <div class="pairTop">
        ${idHtml}
        <div class="pairScore" title="Relevance score based on meaning similarity and shared Arabic roots">score: ${fmtScore(it.score)}</div>
      </div>
      ${body}
      ${sharedBlock}
    `;
    container.appendChild(div);
  }
}

// ── Word / Root modal ───────────────────────────────────────

function sortAyahIds(ids) {
  return [...ids].sort((a, b) => {
    const [as, aa] = a.split(":").map(Number);
    const [bs, ba] = b.split(":").map(Number);
    return as !== bs ? as - bs : aa - ba;
  });
}

function groupBySurah(ayahIds) {
  const groups = new Map();
  for (const id of ayahIds) {
    const s = surahFromAyahId(id);
    if (!groups.has(s)) groups.set(s, []);
    groups.get(s).push(id);
  }
  return groups;
}

function closeWordModal() {
  if (els.wordModal) els.wordModal.classList.add("hidden");
}

async function openWordModal(word, kind) {
  // kind: "root" | "token"
  // Ensure search indexes are available (needed for rootToAyahIds and arTokenToAyah)
  if (!state.enTokenToAyah) await ensureSearchIndex();

  let ayahIds;
  if (kind === "root") {
    ayahIds = state.rootToAyahIds?.[word] || [];
  } else {
    const norm = normalizeArabic(word);
    ayahIds = state.arTokenToAyah?.[norm] || [];
    ayahIds = sortAyahIds(ayahIds);
  }

  const count = ayahIds.length;
  if (!count) return;

  const kindLabel = kind === "root" ? "Root Word" : "Arabic Word";
  els.wordModalTitle.textContent = word;
  els.wordModalSub.textContent   = `${kindLabel} · appears ${count} time${count !== 1 ? "s" : ""} in the Quran`;
  els.wordModalBody.innerHTML    = `<div class="wordModalLoading">Loading ayaat…</div>`;
  els.wordModal.classList.remove("hidden");

  const groups   = groupBySurah(ayahIds);
  const surahs   = [...groups.keys()];

  // Load all needed surahs in parallel (cached shards serve instantly)
  await Promise.all(surahs.map(s => ensureSurahLoaded(s).catch(() => {})));

  // Render grouped by surah
  els.wordModalBody.innerHTML = "";
  for (const surahNum of surahs) {
    const surahNm  = SURAH_NAMES[Number(surahNum)] || "";
    const groupEl  = document.createElement("div");
    groupEl.className = "wordModalGroup";

    const titleEl = document.createElement("div");
    titleEl.className   = "wordModalGroupTitle";
    titleEl.textContent = `Surah ${surahNum}${surahNm ? " — " + surahNm : ""}`;
    groupEl.appendChild(titleEl);

    for (const id of groups.get(surahNum)) {
      const rec  = state.quranById.get(id);
      const item = document.createElement("div");
      item.className = "wordModalItem";
      const modalUrdu = isUrduActive();
      const modalTrans = getQuranTranslation(id);
      const modalDisplayEn = modalTrans || (rec?.english ?? "");
      item.innerHTML = `
        <div class="wordModalItemId">${escapeHtml(fmtAyahId(id))}</div>
        ${rec
          ? `<div class="wordModalItemAr" dir="rtl">${escapeHtml(rec.arabic || "")}</div>
             <div class="wordModalItemEn${modalUrdu ? " urdu-text" : ""}">${escapeHtml(modalDisplayEn)}</div>`
          : `<div class="wordModalLoading">Unavailable</div>`}
      `;
      item.onclick = () => { closeWordModal(); drillTo(id); };
      groupEl.appendChild(item);
    }

    els.wordModalBody.appendChild(groupEl);
  }
}

// Wire modal close
if (els.wordModalClose) els.wordModalClose.onclick = closeWordModal;
if (els.wordModal) els.wordModal.addEventListener("click", e => {
  if (e.target === els.wordModal) closeWordModal();
});
document.addEventListener("keydown", e => {
  if (e.key === "Escape") closeWordModal();
});

// Chip click delegation on the Words & Roots panel
if (els.dRoots) els.dRoots.addEventListener("click", e => {
  const chip = e.target.closest(".rootChip");
  if (chip) openWordModal(chip.textContent.trim(), "root");
});
if (els.dTokens) els.dTokens.addEventListener("click", e => {
  const chip = e.target.closest(".rootChip");
  if (chip) openWordModal(chip.textContent.trim(), "token");
});

// ── Open detail ─────────────────────────────────────────────

// Drill from one anchor to another (pair click, word-modal click).
// Pushes the current anchor onto a back-stack so the user can return.
function drillTo(ayahId) {
  if (state.selectedAyahId && state.selectedAyahId !== ayahId) {
    state.detailHistory.push(state.selectedAyahId);
  }
  openDetail(ayahId, { preserveHistory: true });
}

function goBack() {
  const prev = state.detailHistory.pop();
  if (prev) openDetail(prev, { preserveHistory: true });
}

function updateBackButton() {
  const btn = document.getElementById("backBtn");
  if (!btn) return;
  const depth = state.detailHistory.length;
  if (depth === 0) {
    btn.classList.add("hidden");
    return;
  }
  btn.classList.remove("hidden");
  const prev = state.detailHistory[depth - 1];
  const lbl = btn.querySelector(".backLabel");
  if (lbl) lbl.textContent = typeof fmtAyahId === "function" ? fmtAyahId(prev) : prev;
}

async function openDetail(ayahId, { preserveHistory = false } = {}) {
  const myToken = ++state.detailToken;
  if (!preserveHistory) state.detailHistory = [];
  updateBackButton();
  state.selectedAyahId = ayahId;
  renderResults(state.lastResults, { preserveOrder: true });

  // Show the detail panel immediately with the ayah ID + skeleton pairs
  // so the panel never feels blank while the shard loads.
  setDetailState("detail");
  if (els.dAyahId)  els.dAyahId.textContent  = fmtAyahId(ayahId);
  if (els.dArabic)  els.dArabic.textContent  = "";
  if (els.dEnglish) els.dEnglish.textContent = "";
  showSkeletonPairs(3);

  await ensureSurahLoaded(surahFromAyahId(ayahId));
  if (myToken !== state.detailToken) return;

  const rec   = state.quranById.get(ayahId);
  const pairs = state.pairsByAyah.get(ayahId);
  if (!rec || !pairs) { setDetailState("empty"); return; }

  // Populate anchor card (ayah ID already set above; fill text now that rec is loaded)
  els.dArabic.textContent  = rec.arabic  || "";
  const anchorTrans = getQuranTranslation(ayahId);
  els.dEnglish.textContent = anchorTrans || rec.english || "";
  els.dEnglish.className   = "anchorEnglish" + (isUrduActive() ? " urdu-text" : "");

  // Words & Roots panel — always visible (Phase 3 redesign)
  if (els.dRoots)   els.dRoots.innerHTML   = makeWordChips(rec.roots_ordered  || []);
  if (els.dTokens)  els.dTokens.innerHTML  = makeWordChips(rec.tokens_ordered || []);

  // Tafsir scaffold — async, doesn't block the rest of openDetail
  renderAnchorTafsir(ayahId);

  const MIN_SEM_SCORE = 25;
  const aboveSemMin = p => Number(p.score) >= MIN_SEM_SCORE;
  const semQ = (pairs.semantic?.quran_top20   || []).filter(aboveSemMin);
  const semH = (pairs.semantic?.hadith_top50  || []).filter(aboveSemMin);
  // Lexical Quran pairs use Jaccard root-overlap (0–100); most meaningful pairs
  // score below 25, so skip the score filter — sort by score desc, cap at top 20.
  const lexQ = (pairs.lexical?.quran_all_2plus || pairs.lexical?.quran_top20 || [])
    .slice()
    .sort((a, b) => Number(b.score) - Number(a.score))
    .slice(0, 20);
  const lexH = (pairs.lexical?.hadith_top50   || []).filter(aboveSemMin);

  updateTabCounts(semQ.length, semH.length, lexQ.length, lexH.length);

  renderPairList(els.semQuran, semQ, { kind:"quran",  emptyMessage:"No meaning-based Quran matches found.", sharedTokensLabel:"Shared meaning cues" });
  renderPairList(els.semHadith,semH, { kind:"hadith", emptyMessage:"No meaning-based Hadith matches found.", sharedTokensLabel:"Shared meaning cues" });
  renderPairList(els.lexQuran, lexQ, { kind:"quran",  emptyMessage:"No Quran passages share ≥2 root words with this ayah.", showRootsLine:true, sharedRootsLabel:"Shared root words" });
  renderPairList(els.lexHadith,lexH, { kind:"hadith", emptyMessage:"No word-based Hadith matches found.", showCommonHadithTokens:true, sharedTokensLabel:"Shared Arabic words" });

  const neededSurahs = new Set([
    ...semQ.map(x => surahFromAyahId(x.id)),
    ...lexQ.map(x => surahFromAyahId(x.id))
  ]);

  const firstHadithIds = unique([...semH.slice(0,8).map(x=>x.id), ...lexH.slice(0,8).map(x=>x.id)]);
  const restHadithIds  = unique([...semH.slice(8,20).map(x=>x.id),...lexH.slice(8,20).map(x=>x.id)]);

  await Promise.all([
    loadSurahsParallel([...neededSurahs]),
    preloadHadithIds(firstHadithIds),
    preloadUrHadithShards(firstHadithIds),
  ]);
  if (myToken !== state.detailToken) return;

  renderPairList(els.semQuran, semQ, { kind:"quran",  emptyMessage:"No meaning-based Quran matches found.", sharedTokensLabel:"Shared meaning cues" });
  renderPairList(els.semHadith,semH, { kind:"hadith", emptyMessage:"No meaning-based Hadith matches found.", sharedTokensLabel:"Shared meaning cues" });
  renderPairList(els.lexQuran, lexQ, { kind:"quran",  emptyMessage:"No Quran passages share ≥2 root words with this ayah.", showRootsLine:true, sharedRootsLabel:"Shared root words" });
  renderPairList(els.lexHadith,lexH, { kind:"hadith", emptyMessage:"No word-based Hadith matches found.", showCommonHadithTokens:true, sharedTokensLabel:"Shared Arabic words" });

  preloadHadithIds(restHadithIds).then(() => {
    if (myToken !== state.detailToken) return;
    renderPairList(els.semHadith,semH, { kind:"hadith", emptyMessage:"No meaning-based Hadith matches found.", sharedTokensLabel:"Shared meaning cues" });
    renderPairList(els.lexHadith,lexH, { kind:"hadith", emptyMessage:"No word-based Hadith matches found.", showCommonHadithTokens:true, sharedTokensLabel:"Shared Arabic words" });
  });
}

function warmPreloadTopResults(results) {
  const surahs = unique((results || []).slice(0,8).map(r => surahFromAyahId(r.ayah_id)));
  loadSurahsParallel(surahs).catch(err => console.error("warm preload error:", err));
}

// ── Search run ──────────────────────────────────────────────

async function runSearch() {
  if (state.searchInFlight) return;
  state.searchInFlight = true;

  try {
    const val  = els.mainQuery.value.trim();
    const type = state.activeSearchType;

    state.selectedAyahId = null;
    setDetailState("empty");
    updateTabCounts(0,0,0,0);

    if (!val) {
      setBadge("warn", "Enter a query first");
      renderResults([]);
      return;
    }

    setBadge("warn", type === "smart" ? "Embedding query + reranking… (~3s)" : "Searching…");
    await sleep(0);

    // Ensure search indexes are loaded (no-op if already done by background loader)
    if (type === "en" || type === "ar") {
      if (!state.enTokenToAyah) {
        setBadge("warn", "Loading search index…");
        await ensureSearchIndex();
        setBadge("warn", "Searching…");
      }
    }

    let results = [];
    if      (type === "id")    results = await searchByAyahId(val);
    else if (type === "ar")    results = await searchByArabicKeyword(val);
    else if (type === "smart") results = await searchBySmart(val);
    else                       results = await searchByEnglishSmart(val);

    // Smart Search results are ranked by the reranker; everything else uses ayah order.
    renderResults(results, { preserveOrder: type === "smart" });
    warmPreloadTopResults(results);

    // Show "Did you mean?" only when Smart Search confidence is weak; clear it otherwise.
    if (type === "smart" && results.length > 0) {
      const topScore = typeof results[0]?._rerank_score === "number" ? results[0]._rerank_score : null;
      showSmartHint({ topScore, lang: state.lastSmartLang, query: state.lastSmartQuery });
    } else {
      clearSmartHint();
    }

    let msg = `Found ${results.length} ayat`;
    if (type === "smart" && state.lastSmartCached) msg += " (cached)";
    setBadge("ok", msg);
  } catch (err) {
    console.error("runSearch error:", err);
    setBadge("err", String(err.message || err).slice(0,140));
  } finally {
    state.searchInFlight = false;
  }
}

// ── Buttons & key bindings ──────────────────────────────────

if (els.searchBtn) els.searchBtn.onclick = runSearch;

if (els.clearBtn) els.clearBtn.onclick = () => {
  if (els.mainQuery) els.mainQuery.value = "";
  state.selectedAyahId = null;
  state.lastResults = [];
  state.detailToken++;
  state.modeWasManual = false;
  renderResults([]);
  clearSmartHint();
  setDetailState("empty");
  updateTabCounts(0,0,0,0);
  setBadge("ok", "Ready");
};

if (els.mainQuery) {
  // Enter submits; Shift+Enter inserts a newline (useful for long Smart Search prompts).
  els.mainQuery.addEventListener("keydown", e => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); runSearch(); }
  });
  // Auto-grow the textarea up to ~5 lines, then scroll.
  const autoGrow = () => {
    els.mainQuery.style.height = "auto";
    const max = 5 * 24 + 24; // ~5 lines
    els.mainQuery.style.height = Math.min(els.mainQuery.scrollHeight, max) + "px";
    els.mainQuery.style.overflowY = els.mainQuery.scrollHeight > max ? "auto" : "hidden";
  };
  els.mainQuery.addEventListener("input", autoGrow);
  els.mainQuery.addEventListener("input", applyAutoIntent);
  // Reset height after clearing.
  if (els.clearBtn) els.clearBtn.addEventListener("click", () => {
    els.mainQuery.style.height = "";
    els.mainQuery.style.overflowY = "hidden";
  });
}

if (els.fontIncBtn) els.fontIncBtn.onclick = () => {
  state.arabicFontSize = Math.min(30, state.arabicFontSize + 2);
  document.documentElement.style.setProperty("--arabic-font-size", state.arabicFontSize + "px");
};
if (els.fontDecBtn) els.fontDecBtn.onclick = () => {
  state.arabicFontSize = Math.max(13, state.arabicFontSize - 2);
  document.documentElement.style.setProperty("--arabic-font-size", state.arabicFontSize + "px");
};

if (els.engFontIncBtn) els.engFontIncBtn.onclick = () => {
  state.englishFontSize = Math.min(24, state.englishFontSize + 1);
  document.documentElement.style.setProperty("--english-font-size", state.englishFontSize + "px");
};
if (els.engFontDecBtn) els.engFontDecBtn.onclick = () => {
  state.englishFontSize = Math.max(10, state.englishFontSize - 1);
  document.documentElement.style.setProperty("--english-font-size", state.englishFontSize + "px");
};

// ── Back button (breadcrumb through drilled ayat) ───────────
{
  const back = document.getElementById("backBtn");
  if (back) back.addEventListener("click", goBack);
  document.addEventListener("keydown", e => {
    // Alt + ArrowLeft mirrors browser-style back, only inside the app shell.
    if (e.altKey && e.key === "ArrowLeft" && state.detailHistory.length > 0) {
      e.preventDefault();
      goBack();
    }
  });
}

// ── Header overflow menu (Prophets / Stats / About) ─────────
{
  const btn  = document.getElementById("overflowBtn");
  const menu = document.getElementById("overflowMenu");
  if (btn && menu) {
    const close = () => {
      menu.classList.add("hidden");
      btn.setAttribute("aria-expanded", "false");
    };
    const toggle = () => {
      const isOpen = !menu.classList.contains("hidden");
      if (isOpen) { close(); return; }
      menu.classList.remove("hidden");
      btn.setAttribute("aria-expanded", "true");
    };
    btn.addEventListener("click", e => { e.stopPropagation(); toggle(); });
    // Outside click + Escape closes
    document.addEventListener("click", e => {
      if (menu.classList.contains("hidden")) return;
      if (!menu.contains(e.target) && e.target !== btn) close();
    });
    document.addEventListener("keydown", e => {
      if (e.key === "Escape" && !menu.classList.contains("hidden")) close();
    });
    // Any menu item click closes the menu
    menu.querySelectorAll(".menuItem").forEach(item => {
      item.addEventListener("click", close);
    });
  }
}

// ── Scroll-linked anchor card condense ──────────────────────
{
  const wrap = document.querySelector(".detailScroll");
  if (wrap) {
    const onScroll = () => {
      const condensed = wrap.scrollTop > 32;
      const anchor = document.querySelector(".anchorCard");
      if (anchor) anchor.classList.toggle("condensed", condensed);
    };
    wrap.addEventListener("scroll", onScroll, { passive: true });
  }
}

// ── Lazy search-index loader ────────────────────────────────
// The 4 search index files total ~2.5 MB. We defer them until
// the user actually interacts with search (or idle fires first).

let _searchIndexPromise = null;

async function ensureSearchIndex() {
  if (state.enTokenToAyah) return; // already loaded
  if (_searchIndexPromise)  return _searchIndexPromise;

  _searchIndexPromise = (async () => {
    const m = state.manifest;
    if (!m) throw new Error("Manifest not ready");
    const [enTokenToAyah, enTriToTokens, arTokenToAyah, rootToAyahIds] = await Promise.all([
      fetchJson(m.paths.english_token_to_ayahids),
      fetchJson(m.paths.english_trigram_to_tokens),
      fetchJson(m.paths.arabic_token_to_ayahids),
      fetchJson(m.paths.root_to_ayahids),
    ]);
    state.enTokenToAyah = enTokenToAyah;
    state.enTriToTokens = enTriToTokens;
    state.arTokenToAyah = arTokenToAyah;
    state.rootToAyahIds = rootToAyahIds;
    _searchIndexPromise = null;
  })();

  return _searchIndexPromise;
}

// ── Skeleton helpers ────────────────────────────────────────

function skeletonCard(arLine = true) {
  return `<div class="skeletonCard">
    ${arLine ? `<div class="skeletonLine ar"></div>` : ""}
    <div class="skeletonLine wide"></div>
    <div class="skeletonLine med"></div>
    <div class="skeletonLine short"></div>
  </div>`;
}

function showSkeletonPairs(count = 3) {
  const html = Array.from({ length: count }, () => skeletonCard()).join("");
  [els.semQuran, els.semHadith, els.lexQuran, els.lexHadith].forEach(el => {
    if (el) el.innerHTML = html;
  });
}

// ── Init ────────────────────────────────────────────────────

async function init() {
  try {
    setBadge("warn", "Loading…");
    const manifest = await fetchJson("data/meta/manifest.json");
    state.manifest = manifest;

    // Fetch the 3 shard maps as a single bundled file (1 request instead of 3)
    setBadge("warn", "Loading maps…");
    const bundle = await fetchJson(
      manifest.paths.shard_maps_bundle || "data/meta/shard_maps_bundle.json"
    );
    state.shardMapQuran  = bundle.quran;
    state.shardMapPairs  = bundle.pairs;
    state.shardMapHadith = bundle.hadith;

    setBadge("ok", `Ready — Quran: ${manifest.counts.quran_ayat} | Hadith: ${manifest.counts.hadith}`);
    setDetailState("empty");

    // Load Urdu hadith shard map in background
    if (manifest.paths.ur_hadith_shard_map) {
      fetchJson(manifest.paths.ur_hadith_shard_map)
        .then(sm => { state.urHadithShardMap = sm; })
        .catch(err => console.warn("Urdu hadith shard map load failed:", err));
    }

    // Background: start loading search indexes on idle so they're ready before the user types.
    // requestIdleCallback is used when available (Chrome/Firefox); setTimeout as fallback.
    const startIndexLoad = () => ensureSearchIndex().catch(err => console.warn("Search index preload:", err));
    if (typeof requestIdleCallback !== "undefined") {
      requestIdleCallback(startIndexLoad, { timeout: 4000 });
    } else {
      setTimeout(startIndexLoad, 1000);
    }

    // Background warm-up: preload the most commonly accessed surahs
    // so first searches feel instant. Low-priority — runs after UI is ready.
    setTimeout(() => {
      const warmSurahs = ["1","2","3","4","5","6","7","9","10","12","18","19","20",
                          "21","26","27","28","36","37","38","55","67","112","113","114"];
      Promise.all(warmSurahs.map(s => ensureSurahLoaded(s).catch(() => {})));
    }, 800);

    // Translation switch handler
    if (els.transSel) {
      els.transSel.addEventListener("change", async () => {
        const newId = els.transSel.value;
        if (newId === state.activeTranslation) return;
        if (!state.shardMapQuran) { els.transSel.value = state.activeTranslation; return; } // not ready yet

        const prevId = state.activeTranslation;
        state.activeTranslation = newId;

        // Load translation data if not already cached
        if (newId !== "en_default" && !state.translationData.has(newId)) {
          setBadge("warn", "Loading translation…");
          try {
            await loadTranslation(newId);
          } catch (err) {
            console.error("Translation load error:", err);
            // Roll back — revert to previous translation
            state.activeTranslation = prevId;
            els.transSel.value = prevId;
            setBadge("err", "Translation failed to load — check network");
            return;
          }
        }

        setBadge("ok", "Translation applied");
        // Translation drives default tafsir source — clear sticky choice so it re-picks
        state.activeTafsirSource = null;
        // Re-render everything currently visible with new translation
        renderResults(state.lastResults, { preserveOrder: true });
        if (state.selectedAyahId) openDetail(state.selectedAyahId, { preserveHistory: true });
        renderDailyAyah();
      });
    }

    // Type toggle buttons. Manual click locks the mode until Clear.
    document.querySelectorAll(".typeBtn").forEach(btn => {
      btn.addEventListener("click", () => {
        state.modeWasManual = true;
        setSearchType(btn.dataset.type);
      });
    });

    // Start / About buttons
    if (els.startBtn) {
      els.startBtn.addEventListener("click", () => {
        showLanding(false);
        enterResearchView();
        els.mainQuery.focus();
      });
    }
    if (els.aboutBtn) {
      els.aboutBtn.addEventListener("click", () => showLanding(true));
    }

    // Phase 5 — Mood-first hero
    renderMoodHero();
    wireMoodFirstView();
    renderDailyAyah();

    // Feelings modal
    if (els.feelingsBtn) els.feelingsBtn.addEventListener("click", openFeelingsModal);
    if (els.feelingsModalClose) els.feelingsModalClose.addEventListener("click", closeFeelingsModal);
    if (els.feelingsModal) {
      els.feelingsModal.addEventListener("click", e => {
        if (e.target === els.feelingsModal) closeFeelingsModal();
      });
    }

    // Stats modal
    if (els.statsBtn) els.statsBtn.addEventListener("click", openStatsModal);
    if (els.statsModalClose) els.statsModalClose.addEventListener("click", closeStatsModal);
    if (els.statsModal) {
      els.statsModal.addEventListener("click", e => {
        if (e.target === els.statsModal) closeStatsModal();
      });
    }
    document.querySelectorAll(".statsTab").forEach(btn => {
      btn.addEventListener("click", () => {
        const tab = btn.dataset.stab;
        _statsActiveTab = tab;
        document.querySelectorAll(".statsTab").forEach(t => t.classList.toggle("active", t === btn));
        buildStatsTab(tab);
      });
    });

    // Prophets modal
    if (els.prophetsBtn) els.prophetsBtn.addEventListener("click", openProphetsModal);
    if (els.prophetsModalClose) els.prophetsModalClose.addEventListener("click", closeProphetsModal);
    if (els.prophetsModal) {
      els.prophetsModal.addEventListener("click", e => {
        if (e.target === els.prophetsModal) closeProphetsModal();
      });
    }

    document.addEventListener("keydown", e => {
      if (e.key === "Escape") { closeFeelingsModal(); closeStatsModal(); closeProphetsModal(); closeWordModal(); }
    });

    // Example chips
    document.querySelectorAll(".exampleBtn").forEach(btn => {
      btn.addEventListener("click", () => {
        const type = btn.dataset.type;
        const val  = btn.dataset.value || "";
        setSearchType(type);
        els.mainQuery.value = val;
        showLanding(false);
        enterResearchView();
        runSearch();
      });
    });

  } catch (err) {
    console.error("init error:", err);
    setBadge("err", String(err.message || err).slice(0,140));
  }
}

init();

// Register service worker for persistent JSON caching
if ("serviceWorker" in navigator) {
  navigator.serviceWorker.register("sw.js").catch(() => {});
}
